// lib/email/mailer.ts
import nodemailer from 'nodemailer';

export const transporter = nodemailer.createTransport({
  host: process.env.SMTP_HOST,
  port: parseInt(process.env.SMTP_PORT || '587'),
  secure: process.env.SMTP_PORT === '465',
  auth: {
    user: process.env.SMTP_USER,
    pass: process.env.SMTP_PASSWORD
  }
});

import { render } from '@react-email/render';
import ContactEmail from './templates/ContactEmail';

export async function sendContactEmail({
  to,
  name,
  message
}: ContactRequest) {
  const html = render(ContactEmail({ name, message }));
  return transporter.sendMail({
    from: process.env.SMTP_FROM,
    to,
    subject: 'Contact Confirmation',
    html
  });
}

'use server';
export async function submitContact(formData: FormData) {
  const { email, name, message } = Object.fromEntries(formData);
  // Send confirmation email
  await sendContactEmail({ to: email, name, message });
  // Save to database via Strapi
  const response = await fetch(`${STRAPI_URL}/api/contacts`, {
    method: 'POST',
    body: JSON.stringify({ email, name, message })
  });
  return response.json();
}
